-- Name: FUNCTION auto_approve_contact_updates(min_confirmations integer); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.auto_approve_contact_updates(min_confirmations integer) IS 'Find contact updates that should be auto-approved based on consensus';


--
-- Name: bulk_update_verification(integer[], boolean, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.bulk_update_verification(office_ids integer[], verified_status boolean, verified_by_user text DEFAULT 'admin'::text) RETURNS TABLE(office_id bigint, updated boolean, error_message text)
    LANGUAGE plpgsql
    AS $$
DECLARE
  office_id_val integer;
BEGIN
  FOREACH office_id_val IN ARRAY office_ids
  LOOP
    BEGIN
      UPDATE public.iebc_offices
      SET
        verified = verified_status,
        verified_at = CASE WHEN verified_status THEN NOW() ELSE NULL END,
        verified_by = CASE WHEN verified_status THEN verified_by_user ELSE NULL END,
        updated_at = NOW()
      WHERE id = office_id_val;

      RETURN QUERY
      SELECT office_id_val::bigint, true, NULL::text;

    EXCEPTION WHEN OTHERS THEN
      RETURN QUERY
      SELECT office_id_val::bigint, false, SQLERRM::text;
    END;
  END LOOP;
END;
$$;


ALTER FUNCTION public.bulk_update_verification(office_ids integer[], verified_status boolean, verified_by_user text) OWNER TO postgres;

--
-- Name: FUNCTION bulk_update_verification(office_ids integer[], verified_status boolean, verified_by_user text); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.bulk_update_verification(office_ids integer[], verified_status boolean, verified_by_user text) IS 'Bulk update verification status for multiple offices (admin only)';


--
-- Name: calculate_bounding_box(double precision, double precision, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.calculate_bounding_box(center_lat double precision, center_lon double precision, radius_meters integer) RETURNS text
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
    lat_offset double precision;
    lon_offset double precision;
    min_lat double precision;
    max_lat double precision;
    min_lon double precision;
    max_lon double precision;
BEGIN
    -- Approximate degrees offset for given radius (rough conversion)
    lat_offset := (radius_meters / 111320.0);  -- meters per degree latitude
    lon_offset := (radius_meters / (111320.0 * COS(RADIANS(center_lat))));  -- meters per degree longitude
    
    min_lat := center_lat - lat_offset;
    max_lat := center_lat + lat_offset;
    min_lon := center_lon - lon_offset;
    max_lon := center_lon + lon_offset;
    
    RETURN format('%s,%s,%s,%s', min_lat, min_lon, max_lat, max_lon);
END;
$$;


ALTER FUNCTION public.calculate_bounding_box(center_lat double precision, center_lon double precision, radius_meters integer) OWNER TO postgres;

--
-- Name: calculate_confirmer_distance(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.calculate_confirmer_distance() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  contrib_geom geography;
BEGIN
  SELECT geom INTO contrib_geom 
  FROM public.iebc_office_contributions 
  WHERE id = NEW.contribution_id;
  
  NEW.geom := ST_SetSRID(ST_MakePoint(NEW.confirmer_lng, NEW.confirmer_lat), 4326)::geography;
  NEW.confirmer_distance_meters := ST_Distance(contrib_geom, NEW.geom);
  RETURN NEW;
END;
$$;


ALTER FUNCTION public.calculate_confirmer_distance() OWNER TO postgres;

--
-- Name: charge_usage(uuid, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.charge_usage(p_key_id uuid, p_endpoint_weight integer DEFAULT 1) RETURNS TABLE(allowed boolean, remaining integer, limit_type text, reason text)
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_tier TEXT;
  v_plan_status TEXT;
  v_is_locked BOOLEAN;
  v_credits INTEGER;
  v_monthly_count INTEGER;
  v_monthly_limit INTEGER;
  v_current_period_end TIMESTAMPTZ;
  v_monthly_reset_date DATE;
BEGIN
  -- Fetch key state in a single query
  SELECT
    ak.tier,
    ak.plan_status,
    ak.is_locked,
    ak.credits_balance,
    ak.monthly_request_count,
    ak.current_period_end,
    ak.monthly_reset_date
  INTO
    v_tier, v_plan_status, v_is_locked,
    v_credits, v_monthly_count,
    v_current_period_end, v_monthly_reset_date
  FROM public.api_keys ak
  WHERE ak.id = p_key_id
  FOR UPDATE; -- Lock the row for atomic update

  -- Blocked checks
  IF NOT FOUND THEN
    RETURN QUERY SELECT false, 0, 'unknown'::TEXT, 'Key not found'::TEXT;
    RETURN;
  END IF;

  IF v_is_locked THEN
    RETURN QUERY SELECT false, 0, 'locked'::TEXT, 'Key is locked'::TEXT;
    RETURN;
  END IF;

  IF v_plan_status NOT IN ('active', 'non_renewing') THEN
    RETURN QUERY SELECT false, 0, 'inactive'::TEXT,
      ('Plan status: ' || v_plan_status)::TEXT;
    RETURN;
  END IF;

  -- Reset monthly counter if past reset date
  IF v_monthly_reset_date IS NOT NULL AND CURRENT_DATE > v_monthly_reset_date THEN
    UPDATE public.api_keys SET
      monthly_request_count = 0,
      monthly_reset_date = v_monthly_reset_date + INTERVAL '1 month'
    WHERE id = p_key_id;
    v_monthly_count := 0;
  END IF;

  -- Get the monthly limit for this tier
  v_monthly_limit := public.get_tier_monthly_limit(v_tier);

  -- Route based on billing model
  IF v_tier IN ('enterprise', 'serikali') OR v_credits > 0 THEN
    -- Credit-based billing
    IF v_credits < p_endpoint_weight THEN
      RETURN QUERY SELECT false, v_credits, 'credits'::TEXT,
        'Insufficient credits'::TEXT;
      RETURN;
    END IF;

    UPDATE public.api_keys SET
      credits_balance = credits_balance - p_endpoint_weight,
      requests_today = requests_today + 1,
      last_used_at = NOW()
    WHERE id = p_key_id;

    RETURN QUERY SELECT true, (v_credits - p_endpoint_weight), 'credits'::TEXT,
      'OK'::TEXT;
  ELSE
    -- Monthly-limit billing (free, mwananchi, taifa, etc.)
    IF v_monthly_count >= v_monthly_limit THEN
      RETURN QUERY SELECT false, (v_monthly_limit - v_monthly_count), 'requests'::TEXT,
        'Monthly limit reached'::TEXT;
      RETURN;
    END IF;

    UPDATE public.api_keys SET
      monthly_request_count = monthly_request_count + p_endpoint_weight,
      requests_today = requests_today + 1,
      last_used_at = NOW()
    WHERE id = p_key_id;

    RETURN QUERY SELECT true, (v_monthly_limit - v_monthly_count - p_endpoint_weight),
      'requests'::TEXT, 'OK'::TEXT;
  END IF;
END;
$$;


ALTER FUNCTION public.charge_usage(p_key_id uuid, p_endpoint_weight integer) OWNER TO postgres;

--
-- Name: FUNCTION charge_usage(p_key_id uuid, p_endpoint_weight integer); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.charge_usage(p_key_id uuid, p_endpoint_weight integer) IS 'Unified billing RPC — routes between credit deduction and monthly request counting based on tier. Prevents double-taxing.';


--
-- Name: check_auto_verification(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.check_auto_verification() RETURNS trigger
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_contribution record;
  v_unique_confirmers integer;
  v_unique_ip_prefixes integer;
  v_avg_distance double precision;
  v_total_weight integer;
BEGIN
  -- Fetch contribution details
  SELECT * INTO v_contribution 
  FROM public.iebc_office_contributions 
  WHERE id = NEW.contribution_id;
  
  -- Calculate confirmation metrics
  SELECT 
    COUNT(DISTINCT confirmer_device_hash) as unique_devices,
    COUNT(DISTINCT substring(confirmer_ip_hash, 1, 8)) as unique_ip_prefixes,
    AVG(confirmer_distance_meters) as avg_distance,
    SUM(confirmation_weight) as total_weight
  INTO 
    v_unique_confirmers, v_unique_ip_prefixes, v_avg_distance, v_total_weight
  FROM public.confirmations
  WHERE contribution_id = NEW.contribution_id
    AND confirmed_at >= now() - interval '90 days';
  
  -- Auto-verification thresholds
  IF v_unique_confirmers >= 5 
     AND v_unique_ip_prefixes >= 3 
     AND v_avg_distance <= 300 
     AND v_total_weight >= 10 
     AND v_contribution.confidence_score >= 60 
     AND v_contribution.status = 'pending' THEN
    
    -- Auto-promote to verified
    UPDATE public.iebc_office_contributions 
    SET 
      status = 'auto_verified',
      review_notes = format('Auto-verified via community: %s confirmers, avg distance %sm, total weight %s', 
                           v_unique_confirmers, round(v_avg_distance), v_total_weight),
      reviewed_at = now()
    WHERE id = NEW.contribution_id;
    
    -- Log auto-verification
    INSERT INTO public.verification_log (
      contribution_id, action, actor, details
    ) VALUES (
      NEW.contribution_id, 'verified', 'system:auto_verification',
      jsonb_build_object(
        'unique_confirmers', v_unique_confirmers,
        'unique_ip_prefixes', v_unique_ip_prefixes,
        'avg_distance_meters', v_avg_distance,
        'total_weight', v_total_weight,
        'confidence_score', v_contribution.confidence_score
      )
    );
  END IF;
  
  RETURN NEW;
END;
$$;


ALTER FUNCTION public.check_auto_verification() OWNER TO postgres;

--
-- Name: check_submission_rate_limit(text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.check_submission_rate_limit(p_ip_hash text, p_device_hash text) RETURNS TABLE(allowed boolean, reason text, retry_after_seconds integer)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_ip_count integer;
  v_device_count integer;
BEGIN
  -- Check IP-based rate limit (5 per hour)
  SELECT COUNT(*) INTO v_ip_count
  FROM public.iebc_office_contributions
  WHERE device_metadata->>'ip_hash' = p_ip_hash
    AND created_at >= now() - interval '1 hour';
  
  IF v_ip_count >= 5 THEN
    RETURN QUERY SELECT false, 'IP rate limit exceeded', 3600;
    RETURN;
  END IF;
  
  -- Check device-based rate limit (20 per day)
  SELECT COUNT(*) INTO v_device_count
  FROM public.iebc_office_contributions
  WHERE device_fingerprint_hash = p_device_hash
    AND created_at >= now() - interval '24 hours';
  
  IF v_device_count >= 20 THEN
    RETURN QUERY SELECT false, 'Device rate limit exceeded', 86400;
    RETURN;
  END IF;
  
  RETURN QUERY SELECT true, 'OK'::text, 0;
END;
$$;


ALTER FUNCTION public.check_submission_rate_limit(p_ip_hash text, p_device_hash text) OWNER TO postgres;

