--
-- Name: confirm_iebc_2027_centre(text, character, text, text, jsonb, timestamp with time zone, timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.confirm_iebc_2027_centre(p_city text, p_country_code character, p_gazette_ref text, p_source_url text, p_services jsonb DEFAULT '["voter_registration"]'::jsonb, p_reg_opens timestamp with time zone DEFAULT NULL::timestamp with time zone, p_reg_closes timestamp with time zone DEFAULT NULL::timestamp with time zone, p_voting_date timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
  v_id UUID;
BEGIN
  UPDATE public.diaspora_registration_centres
  SET
    is_iebc_confirmed_2027     = true,
    confirmed_2027_gazette_ref = p_gazette_ref,
    confirmed_2027_source_url  = p_source_url,
    services_2027              = p_services,
    registration_opens_at      = p_reg_opens,
    registration_closes_at     = p_reg_closes,
    voting_date                = p_voting_date
  WHERE
    LOWER(city) = LOWER(p_city)
    AND country_code = p_country_code
  RETURNING id INTO v_id;

  RETURN v_id;
END;
$$;


