--
-- Name: find_duplicate_offices(double precision, double precision, text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.find_duplicate_offices(p_lat double precision, p_lng double precision, p_name text, p_radius_meters integer DEFAULT 200) RETURNS TABLE(id bigint, office_location text, constituency_name text, county text, latitude double precision, longitude double precision, distance_meters double precision, is_likely_duplicate boolean)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    io.id,
    io.office_location,
    io.constituency_name,
    io.county,
    io.latitude,
    io.longitude,
    ST_Distance(
      io.geom::geometry,
      ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography
    ) as distance_meters,
    CASE 
      WHEN ST_Distance(
        io.geom::geometry,
        ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography
      ) <= p_radius_meters THEN true
      ELSE false
    END as is_likely_duplicate
  FROM iebc_offices io
  WHERE io.verified = true
    AND ST_DWithin(
      io.geom::geometry,
      ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography,
      p_radius_meters
    )
  ORDER BY distance_meters ASC;
END;
$$;


ALTER FUNCTION public.find_duplicate_offices(p_lat double precision, p_lng double precision, p_name text, p_radius_meters integer) OWNER TO postgres;

