CREATE FUNCTION public.find_nearby_offices(lat double precision, lon double precision, radius double precision DEFAULT 500) RETURNS TABLE(id bigint, office_location text, latitude double precision, longitude double precision, distance double precision)
    LANGUAGE plpgsql
