--
-- Name: find_nearest_kenyan_mission(double precision, double precision, public.diaspora_centre_state, text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.find_nearest_kenyan_mission(search_lat double precision, search_lng double precision, filter_state public.diaspora_centre_state DEFAULT NULL::public.diaspora_centre_state, filter_continent text DEFAULT NULL::text, max_results integer DEFAULT 5) RETURNS TABLE(id uuid, mission_name text, mission_type text, city text, country text, country_code text, continent text, latitude double precision, longitude double precision, address text, phone text, email text, website_url text, whatsapp text, designation_state public.diaspora_centre_state, designation_count integer, designated_2017 boolean, designated_2022 boolean, is_iebc_confirmed_2027 boolean, services_2027 jsonb, registration_opens_at timestamp with time zone, registration_closes_at timestamp with time zone, inquiry_notes text, distance_km double precision)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    d.id,
    d.mission_name,
    d.mission_type,
    d.city,
    d.country,
    d.country_code::TEXT,
    d.continent,
    d.latitude,
    d.longitude,
    d.address,
    d.phone,
    d.email,
    d.website_url,
    d.whatsapp,
    d.designation_state,
    d.designation_count,
    d.designated_2017,
    d.designated_2022,
    d.is_iebc_confirmed_2027,
    d.services_2027,
    d.registration_opens_at,
    d.registration_closes_at,
    d.inquiry_notes,
    (6371 * acos(
      LEAST(1.0, GREATEST(-1.0,
        cos(radians(search_lat)) * cos(radians(d.latitude)) *
        cos(radians(d.longitude) - radians(search_lng)) +
        sin(radians(search_lat)) * sin(radians(d.latitude))
      ))
    ))::FLOAT AS distance_km
  FROM public.diaspora_registration_centres d
  WHERE
    d.is_active = true
    AND d.latitude IS NOT NULL
    AND d.longitude IS NOT NULL
    AND (filter_state IS NULL OR d.designation_state = filter_state)
    AND (filter_continent IS NULL OR d.continent = filter_continent)
  ORDER BY distance_km ASC
  LIMIT max_results;
END;
$$;


ALTER FUNCTION public.find_nearest_kenyan_mission(search_lat double precision, search_lng double precision, filter_state public.diaspora_centre_state, filter_continent text, max_results integer) OWNER TO postgres;

--
-- Name: find_offices_near_place(double precision, double precision, double precision, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.find_offices_near_place(search_lat double precision, search_lng double precision, radius_km double precision DEFAULT 15, max_results integer DEFAULT 20) RETURNS TABLE(id integer, county text, constituency_name text, constituency text, office_location text, latitude double precision, longitude double precision, verified boolean, formatted_address text, landmark text, clean_office_location text, distance_km double precision)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
  RETURN QUERY
  WITH
  -- Step 1: Bounding box pre-filter (fast index scan on lat/lng)
  candidates AS (
    SELECT o.*
    FROM public.iebc_offices o
    WHERE
      o.latitude IS NOT NULL
      AND o.longitude IS NOT NULL
      AND o.verified = true
      AND o.latitude BETWEEN search_lat - (radius_km / 111.0)
                         AND search_lat + (radius_km / 111.0)
      AND o.longitude BETWEEN search_lng - (radius_km / (111.0 * cos(radians(search_lat))))
                           AND search_lng + (radius_km / (111.0 * cos(radians(search_lat))))
  ),
  -- Step 2: Exact Haversine distance calculation
  with_distance AS (
    SELECT
      c.id,
      c.county,
      c.constituency_name,
      c.constituency,
      c.office_location,
      c.latitude,
      c.longitude,
      c.verified,
      c.formatted_address,
      c.landmark,
      c.clean_office_location,
      (6371 * acos(
        LEAST(1.0, GREATEST(-1.0,
          cos(radians(search_lat)) * cos(radians(c.latitude)) *
          cos(radians(c.longitude) - radians(search_lng)) +
          sin(radians(search_lat)) * sin(radians(c.latitude))
        ))
      ))::FLOAT AS distance_km
    FROM candidates c
  )
  -- Step 3: Filter by exact radius and sort by distance
  SELECT wd.*
  FROM with_distance wd
  WHERE wd.distance_km <= radius_km
  ORDER BY wd.distance_km ASC
  LIMIT max_results;
END;
$$;


ALTER FUNCTION public.find_offices_near_place(search_lat double precision, search_lng double precision, radius_km double precision, max_results integer) OWNER TO postgres;

--
-- Name: fix_all_constituency_relationships(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.fix_all_constituency_relationships() RETURNS TABLE(offices_updated bigint, contributions_updated bigint)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  office_count bigint;
  contribution_count bigint;
BEGIN
  -- Fix iebc_offices
  WITH updated_offices AS (
    UPDATE iebc_offices o
    SET constituency_code = get_or_create_constituency(o.constituency, o.county)
    WHERE constituency_code IS NULL 
      AND o.constituency IS NOT NULL 
      AND o.constituency != ''
    RETURNING 1
  )
  SELECT COUNT(*) INTO office_count FROM updated_offices;

  -- Fix iebc_office_contributions
  WITH updated_contributions AS (
    UPDATE iebc_office_contributions c
    SET submitted_constituency_code = get_or_create_constituency(
      c.submitted_constituency, 
      c.submitted_county
    )
    WHERE submitted_constituency_code IS NULL 
      AND c.submitted_constituency IS NOT NULL 
      AND c.submitted_constituency != ''
    RETURNING 1
  )
  SELECT COUNT(*) INTO contribution_count FROM updated_contributions;

  RETURN QUERY SELECT office_count, contribution_count;
END;
$$;


ALTER FUNCTION public.fix_all_constituency_relationships() OWNER TO postgres;

--
-- Name: fix_constituency_references(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.fix_constituency_references() RETURNS void
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  -- Update iebc_offices with valid constituency codes
  UPDATE iebc_offices 
  SET constituency_code = c.id
  FROM constituencies c 
  WHERE iebc_offices.constituency = c.name 
    AND iebc_offices.constituency_code IS NULL;
    
  -- Update contributions with valid constituency IDs
  UPDATE iebc_office_contributions 
  SET submitted_constituency_id = c.id
  FROM constituencies c 
  WHERE iebc_office_contributions.submitted_constituency = c.name 
    AND iebc_office_contributions.submitted_constituency_id IS NULL;
END;
$$;


ALTER FUNCTION public.fix_constituency_references() OWNER TO postgres;

--
-- Name: get_constituency_code(text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_constituency_code(p_constituency_name text, p_county_name text) RETURNS TABLE(id integer)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    c.id
  FROM 
    constituencies c
  WHERE 
    c.name ILIKE '%' || p_constituency_name || '%'
    AND c.county_name ILIKE '%' || p_county_name || '%'
  LIMIT 1;
END;
$$;


ALTER FUNCTION public.get_constituency_code(p_constituency_name text, p_county_name text) OWNER TO postgres;

--
-- Name: get_constituency_from_coords(double precision, double precision); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_constituency_from_coords(p_lat double precision, p_lng double precision) RETURNS TABLE(constituency_name text, county_name text, constituency_id integer)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    c.name as constituency_name,
    c.county_name,
    c.id as constituency_id
  FROM 
    constituencies c
  WHERE 
    ST_Contains(
      c.geom,
      ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)
    )
  LIMIT 1;
END;
$$;


