--
-- Name: get_constituency_mapping_stats(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_constituency_mapping_stats() RETURNS TABLE(total_contributions bigint, with_constituency_codes bigint, without_constituency_codes bigint, mapping_success_rate numeric)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    COUNT(*) as total_contributions,
    COUNT(*) FILTER (WHERE submitted_constituency_code IS NOT NULL) as with_constituency_codes,
    COUNT(*) FILTER (WHERE submitted_constituency_code IS NULL) as without_constituency_codes,
    ROUND(
      (COUNT(*) FILTER (WHERE submitted_constituency_code IS NOT NULL) * 100.0 / 
      NULLIF(COUNT(*), 0)), 2
    ) as mapping_success_rate
  FROM iebc_office_contributions;
END;
$$;


ALTER FUNCTION public.get_constituency_mapping_stats() OWNER TO postgres;

