--
-- Name: get_county_stats(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_county_stats() RETURNS TABLE(county text, office_count bigint, mapped_count bigint, verified_count bigint)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        o.county,
        COUNT(o.id) as office_count,
        COUNT(CASE WHEN o.latitude IS NOT NULL THEN 1 END) as mapped_count,
        COUNT(CASE WHEN o.verified = true THEN 1 END) as verified_count
    FROM public.iebc_offices o
    GROUP BY o.county
    ORDER BY o.county ASC;
END;
$$;


