--
-- Name: get_most_verified_offices(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_most_verified_offices(limit_count integer DEFAULT 20) RETURNS TABLE(office_id integer, county text, constituency_name text, confirmation_count bigint, avg_weight numeric, last_confirmed_at timestamp with time zone)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    o.id AS office_id,
    o.county,
    o.constituency_name,
    COUNT(DISTINCT c.id) AS confirmation_count,
    AVG(c.confirmation_weight) AS avg_weight,
    MAX(c.confirmed_at) AS last_confirmed_at
  FROM public.iebc_offices o
  JOIN public.iebc_office_contributions cont ON o.id = cont.original_office_id
  JOIN public.confirmations c ON cont.id = c.contribution_id
  WHERE o.verified = true
  GROUP BY o.id, o.county, o.constituency_name
  ORDER BY confirmation_count DESC, avg_weight DESC
  LIMIT limit_count;
END;
$$;


ALTER FUNCTION public.get_most_verified_offices(limit_count integer) OWNER TO postgres;

--
-- Name: get_nearby_iebc_offices(double precision, double precision, double precision); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_nearby_iebc_offices(p_lat double precision, p_lng double precision, p_radius double precision) RETURNS TABLE(office_id bigint, office_name text, office_location text, county text, constituency_name text, constituency_code integer, office_latitude double precision, office_longitude double precision, office_landmark text, office_landmark_type text, distance_meters double precision, office_direction_type text, office_direction_landmark text, office_direction_distance double precision)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        io.id as office_id,
        io.office_location as office_name,
        io.office_location,
        io.county,
        io.constituency_name,
        io.constituency_code,
        COALESCE(io.verified_latitude, io.latitude) as office_latitude,
        COALESCE(io.verified_longitude, io.longitude) as office_longitude,
        io.landmark as office_landmark,
        io.landmark_type as office_landmark_type,
        ST_Distance(
            ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography,
            ST_SetSRID(ST_MakePoint(
                COALESCE(io.verified_longitude, io.longitude), 
                COALESCE(io.verified_latitude, io.latitude)
            ), 4326)::geography
        ) as distance_meters,
        io.direction_type as office_direction_type,
        io.direction_landmark as office_direction_landmark,
        io.direction_distance as office_direction_distance
    FROM 
        iebc_offices io
    WHERE 
        io.verified = true
        AND ST_DWithin(
            ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography,
            ST_SetSRID(ST_MakePoint(
                COALESCE(io.verified_longitude, io.longitude), 
                COALESCE(io.verified_latitude, io.latitude)
            ), 4326)::geography,
            p_radius
        )
    ORDER BY 
        distance_meters ASC
    LIMIT 15;
END;
$$;


ALTER FUNCTION public.get_nearby_iebc_offices(p_lat double precision, p_lng double precision, p_radius double precision) OWNER TO postgres;

--
-- Name: get_nearby_landmarks(double precision, double precision, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_nearby_landmarks(p_lat double precision, p_lng double precision, p_radius_meters integer DEFAULT 500) RETURNS TABLE(id uuid, name text, landmark_type text, landmark_subtype text, distance_meters double precision)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    ml.id,
    ml.name,
    ml.landmark_type,
    ml.landmark_subtype,
    ST_Distance(
      ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography,
      ml.geom::geography
    ) as distance_meters
  FROM 
    map_landmarks ml
  WHERE 
    ST_DWithin(
      ST_SetSRID(ST_MakePoint(p_lng, p_lat), 4326)::geography,
      ml.geom::geography,
      p_radius_meters
    )
  ORDER BY 
    distance_meters ASC
  LIMIT 10;
END;
$$;


ALTER FUNCTION public.get_nearby_landmarks(p_lat double precision, p_lng double precision, p_radius_meters integer) OWNER TO postgres;

--
-- Name: get_nearest_ward(double precision, double precision); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.get_nearest_ward(lat_param double precision, lng_param double precision) RETURNS TABLE(id uuid, ward_name text, constituency text, county text, latitude double precision, longitude double precision, distance_km double precision)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        w.id,
        w.ward_name,
        w.constituency,
        w.county,
        w.latitude,
        w.longitude,
        (6371 * acos(
            cos(radians(lat_param)) * cos(radians(w.latitude)) * 
            cos(radians(w.longitude) - radians(lng_param)) + 
            sin(radians(lat_param)) * sin(radians(w.latitude))
        )) as distance_km
    FROM public.wards w
    WHERE w.latitude IS NOT NULL AND w.longitude IS NOT NULL
    ORDER BY (
        point(w.longitude, w.latitude) <-> point(lng_param, lat_param)
    ) ASC
    LIMIT 1;
END;
$$;


ALTER FUNCTION public.get_nearest_ward(lat_param double precision, lng_param double precision) OWNER TO postgres;

