--
-- Name: map_osm_element_to_landmark(json); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.map_osm_element_to_landmark(element_data json) RETURNS TABLE(landmark_type text, landmark_subtype text, name text, latitude double precision, longitude double precision, accuracy_meters integer, visibility_score integer, permanence_score integer, triangulation_weight double precision)
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
    tags json;
    element_type text;
    center_lat double precision;
    center_lon double precision;
BEGIN
    tags := element_data -> 'tags';
    element_type := element_data ->> 'type';
    
    -- Extract coordinates for node / way / relation (use center where available)
    IF element_type = 'node' THEN
        IF (element_data ->> 'lat') IS NULL OR (element_data ->> 'lon') IS NULL THEN
            RETURN; -- no coordinates
        END IF;
        center_lat := (element_data ->> 'lat')::double precision;
        center_lon := (element_data ->> 'lon')::double precision;
        
    ELSIF element_type = 'way' OR element_type = 'relation' THEN
        IF element_data ? 'center' THEN
            center_lat := (element_data -> 'center' ->> 'lat')::double precision;
            center_lon := (element_data -> 'center' ->> 'lon')::double precision;
        ELSIF element_data ? 'geometry' AND json_array_length(element_data -> 'geometry') > 0 THEN
            center_lat := (element_data -> 'geometry' -> 0 ->> 'lat')::double precision;
            center_lon := (element_data -> 'geometry' -> 0 ->> 'lon')::double precision;
        ELSIF element_data ? 'bounds' THEN
            -- use bounding box center if available
            center_lat := (((element_data -> 'bounds' ->> 'minlat')::double precision + (element_data -> 'bounds' ->> 'maxlat')::double precision) / 2.0);
            center_lon := (((element_data -> 'bounds' ->> 'minlon')::double precision + (element_data -> 'bounds' ->> 'maxlon')::double precision) / 2.0);
        ELSE
            RETURN; -- no usable coordinate
        END IF;
    ELSE
        RETURN; -- unsupported element type
    END IF;
    
    -- Extract name or useful identifiers
    name := COALESCE(
        tags ->> 'name',
        tags ->> 'name:en',
        tags ->> 'ref',
        tags ->> 'operator',
        tags ->> 'addr:housename',
        tags ->> 'addr:housenumber'
    );

    -- Default baseline (if nothing matches)
    accuracy_meters := 25;
    visibility_score := 5;
    permanence_score := 6;
    triangulation_weight := 0.5;

    -- Map common OSM tags to landmark types and set heuristics
    IF tags IS NOT NULL AND tags ->> 'highway' IS NOT NULL THEN
        landmark_type := 'road';
        landmark_subtype := tags ->> 'highway';
        accuracy_meters := 8;
        visibility_score := 9;
        permanence_score := 10;
        triangulation_weight := 0.85;

    ELSIF tags IS NOT NULL AND tags ->> 'railway' IS NOT NULL THEN
        landmark_type := 'railway';
        landmark_subtype := tags ->> 'railway';
        accuracy_meters := 8;
        visibility_score := 9;
        permanence_score := 10;
        triangulation_weight := 0.85;

    ELSIF tags IS NOT NULL AND tags ->> 'aeroway' IS NOT NULL THEN
        landmark_type := 'aeroway';
        landmark_subtype := tags ->> 'aeroway';
        accuracy_meters := 20;
        visibility_score := 10;
        permanence_score := 10;
        triangulation_weight := 0.9;

    ELSIF tags IS NOT NULL AND tags ->> 'waterway' IS NOT NULL THEN
        landmark_type := 'waterway';
        landmark_subtype := tags ->> 'waterway';
        accuracy_meters := 15;
        visibility_score := 7;
        permanence_score := 9;
        triangulation_weight := 0.7;

    ELSIF tags IS NOT NULL AND tags ->> 'natural' IS NOT NULL THEN
        landmark_type := 'natural';
        landmark_subtype := tags ->> 'natural';
        accuracy_meters := CASE WHEN tags ->> 'natural' = 'peak' THEN 5 ELSE 15 END;
        visibility_score := 8;
        permanence_score := 10;
        triangulation_weight := 0.85;

    ELSIF tags IS NOT NULL AND tags ->> 'landuse' IS NOT NULL THEN
        landmark_type := 'landuse';
        landmark_subtype := tags ->> 'landuse';
        accuracy_meters := 25;
        visibility_score := 6;
        permanence_score := 8;
        triangulation_weight := 0.6;

    ELSIF tags IS NOT NULL AND tags ->> 'amenity' IS NOT NULL THEN
        landmark_type := 'amenity';
        landmark_subtype := tags ->> 'amenity';
        accuracy_meters := 10;
        visibility_score := 9;
        permanence_score := 9;
        triangulation_weight := CASE 
            WHEN tags ->> 'amenity' IN ('hospital','police','fire_station','townhall','courthouse') THEN 0.9
            WHEN tags ->> 'amenity' IN ('school','university') THEN 0.85
            ELSE 0.75
        END;

    ELSIF tags IS NOT NULL AND tags ->> 'shop' IS NOT NULL THEN
        landmark_type := 'shop';
        landmark_subtype := tags ->> 'shop';
        accuracy_meters := 12;
        visibility_score := 7;
        permanence_score := 7;
        triangulation_weight := 0.65;

    ELSIF tags IS NOT NULL AND tags ->> 'tourism' IS NOT NULL THEN
        landmark_type := 'tourism';
        landmark_subtype := tags ->> 'tourism';
        accuracy_meters := 12;
        visibility_score := 8;
        permanence_score := 8;
        triangulation_weight := 0.75;

    ELSIF tags IS NOT NULL AND tags ->> 'historic' IS NOT NULL THEN
        landmark_type := 'historic';
        landmark_subtype := tags ->> 'historic';
        accuracy_meters := 10;
        visibility_score := 8;
        permanence_score := 9;
        triangulation_weight := 0.78;

    ELSIF tags IS NOT NULL AND tags ->> 'leisure' IS NOT NULL THEN
        landmark_type := 'leisure';
        landmark_subtype := tags ->> 'leisure';
        accuracy_meters := 20;
        visibility_score := 6;
        permanence_score := 7;
        triangulation_weight := 0.6;

    ELSIF tags IS NOT NULL AND tags ->> 'power' IS NOT NULL THEN
        landmark_type := 'infrastructure';
        landmark_subtype := tags ->> 'power';
        accuracy_meters := 10;
        visibility_score := 9;
        permanence_score := 10;
        triangulation_weight := 0.88;

    ELSIF tags IS NOT NULL AND tags ->> 'man_made' IS NOT NULL THEN
        landmark_type := 'man_made';
        landmark_subtype := tags ->> 'man_made';
        accuracy_meters := 12;
        visibility_score := 7;
        permanence_score := 9;
        triangulation_weight := 0.75;

    ELSIF tags IS NOT NULL AND tags ->> 'communication' IS NOT NULL THEN
        landmark_type := 'communication';
        landmark_subtype := tags ->> 'communication';
        accuracy_meters := 10;
        visibility_score := 9;
        permanence_score := 10;
        triangulation_weight := 0.85;

    ELSIF tags IS NOT NULL AND tags ->> 'addr:housenumber' IS NOT NULL THEN
        landmark_type := 'address';
        landmark_subtype := COALESCE(tags ->> 'addr:street', 'address');
        -- address points are quite precise but transient
        accuracy_meters := 5;
        visibility_score := 6;
        permanence_score := 6;
        triangulation_weight := 0.6;

    ELSIF tags IS NOT NULL AND tags ->> 'boundary' IS NOT NULL THEN
        landmark_type := 'boundary';
        landmark_subtype := COALESCE(tags ->> 'admin_level', tags ->> 'boundary');
        accuracy_meters := 30;
        visibility_score := 4;
        permanence_score := 9;
        triangulation_weight := 0.6;

    ELSIF tags IS NOT NULL AND tags ->> 'building' IS NOT NULL THEN
        landmark_type := 'building';
        landmark_subtype := tags ->> 'building';
        accuracy_meters := 8;
        visibility_score := 8;
        permanence_score := 9;
        triangulation_weight := 0.8;

    ELSIF tags IS NOT NULL AND (tags ->> 'emergency') IS NOT NULL THEN
        landmark_type := 'emergency';
        landmark_subtype := tags ->> 'emergency';
        accuracy_meters := 12;
        visibility_score := 8;
        permanence_score := 9;
        triangulation_weight := 0.8;

    -- fallback: any element with a name should be considered a POI
    ELSIF name IS NOT NULL THEN
        landmark_type := 'poi';
        landmark_subtype := NULL;
        accuracy_meters := 20;
        visibility_score := 6;
        permanence_score := 6;
        triangulation_weight := 0.55;

    ELSE
        -- Skip unmapped elements
        RETURN;
    END IF;
    
    -- Return the mapped values
    RETURN QUERY SELECT 
        landmark_type, landmark_subtype, name,
        center_lat, center_lon, accuracy_meters,
        visibility_score, permanence_score, triangulation_weight;
END;
$$;


ALTER FUNCTION public.map_osm_element_to_landmark(element_data json) OWNER TO postgres;

--
-- Name: normalize_county_name(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.normalize_county_name(name text) RETURNS text
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $_$
BEGIN
    RETURN LOWER(
        REGEXP_REPLACE(
            REGEXP_REPLACE(
                REGEXP_REPLACE(
                    REGEXP_REPLACE(
                        REGEXP_REPLACE($1, 
                        '\s*CITY\s*', '', 'i'), -- Remove 'CITY'
                    '[-''()]', ' ', 'g'),      -- Replace special chars with space
                '[^a-z0-9\s]', '', 'g'),       -- Remove remaining non-alphanumeric
            '\s+', ' ', 'g'),                 -- Collapse multiple spaces
        ' ', '', 'g')                         -- Remove all spaces
    );
END;
$_$;


ALTER FUNCTION public.normalize_county_name(name text) OWNER TO postgres;

--
-- Name: normalize_text(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.normalize_text(text_to_normalize text) RETURNS text
    LANGUAGE plpgsql IMMUTABLE
    SET search_path TO 'public', 'pg_temp'
    AS $$
BEGIN
    -- Convert to lowercase, remove all non-alphanumeric characters, and trim whitespace
    RETURN regexp_replace(lower(trim(text_to_normalize)), '[^a-z0-9]', '', 'g');
END;
$$;


ALTER FUNCTION public.normalize_text(text_to_normalize text) OWNER TO postgres;

--
-- Name: promote_contribution_to_office(bigint, text, jsonb); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.promote_contribution_to_office(p_contribution_id bigint, p_admin_id text, p_office_data jsonb DEFAULT '{}'::jsonb) RETURNS jsonb
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
    v_contribution_record record;
    v_existing_office_id bigint;
    v_constituency_name text;
    v_constituency_id integer;
    v_office_id bigint;
    v_action_taken text;
    v_exact_constituency_name text;
    v_debug_info jsonb;
BEGIN
    -- Get the contribution data
    SELECT * INTO v_contribution_record 
    FROM iebc_office_contributions 
    WHERE id = p_contribution_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('error', 'Contribution not found');
    END IF;
    
    -- Initialize debug info
    v_debug_info := jsonb_build_object(
        'original_constituency', v_contribution_record.submitted_constituency,
        'original_constituency_code', v_contribution_record.submitted_constituency_code
    );
    
    -- Handle constituency
    v_constituency_name := v_contribution_record.submitted_constituency;
    v_constituency_id := v_contribution_record.submitted_constituency_code;
    
    -- If constituency_code is null, try to find by name
    IF v_constituency_id IS NULL THEN
        SELECT id, name INTO v_constituency_id, v_exact_constituency_name
        FROM constituencies 
        WHERE LOWER(TRIM(name)) = LOWER(TRIM(v_constituency_name))
        LIMIT 1;
        
        IF v_constituency_id IS NOT NULL THEN
            v_constituency_name := v_exact_constituency_name;
            v_debug_info := v_debug_info || jsonb_build_object('found_by_name', true, 'found_id', v_constituency_id);
        ELSE
            -- Try fuzzy matching if exact match fails
            SELECT id, name INTO v_constituency_id, v_exact_constituency_name
            FROM constituencies 
            WHERE LOWER(name) LIKE LOWER('%' || v_constituency_name || '%')
            LIMIT 1;
            
            IF v_constituency_id IS NOT NULL THEN
                v_constituency_name := v_exact_constituency_name;
                v_debug_info := v_debug_info || jsonb_build_object('found_by_fuzzy', true, 'found_id', v_constituency_id);
            ELSE
                -- Last resort: use a known valid constituency
                SELECT id, name INTO v_constituency_id, v_constituency_name
                FROM constituencies 
                WHERE name = 'EMBAKASI WEST'
                LIMIT 1;
                
                IF v_constituency_id IS NULL THEN
                    -- Ultimate fallback
                    SELECT id, name INTO v_constituency_id, v_constituency_name
                    FROM constituencies 
                    LIMIT 1;
                END IF;
                
                v_debug_info := v_debug_info || jsonb_build_object('used_fallback', true, 'fallback_id', v_constituency_id);
            END IF;
        END IF;
    ELSE
        -- Check if constituency ID exists
        IF EXISTS(SELECT 1 FROM constituencies WHERE id = v_constituency_id) THEN
            SELECT name INTO v_exact_constituency_name 
            FROM constituencies 
            WHERE id = v_constituency_id;
            
            IF v_exact_constituency_name IS NOT NULL THEN
                v_constituency_name := v_exact_constituency_name;
            END IF;
        ELSE
            -- Invalid ID, find by name
            SELECT id, name INTO v_constituency_id, v_exact_constituency_name
            FROM constituencies 
            WHERE LOWER(TRIM(name)) = LOWER(TRIM(v_constituency_name))
            LIMIT 1;
            
            IF v_constituency_id IS NULL THEN
                -- Try fuzzy matching
                SELECT id, name INTO v_constituency_id, v_exact_constituency_name
                FROM constituencies 
                WHERE LOWER(name) LIKE LOWER('%' || v_constituency_name || '%')
                LIMIT 1;
            END IF;
        END IF;
    END IF;
    
    -- Final safety check
    IF v_constituency_id IS NULL OR NOT EXISTS(SELECT 1 FROM constituencies WHERE id = v_constituency_id) THEN
        RETURN jsonb_build_object(
            'error', 'No valid constituency found',
            'debug', v_debug_info,
            'contribution_constituency', v_contribution_record.submitted_constituency,
            'final_constituency_id', v_constituency_id
        );
    END IF;
    
    -- SIMPLE EXACT MATCHING
    SELECT id INTO v_existing_office_id 
    FROM iebc_offices 
    WHERE constituency_code = v_constituency_id 
    AND office_location = v_contribution_record.submitted_office_location;
    
    IF v_existing_office_id IS NOT NULL THEN
        -- UPDATE existing office
        UPDATE iebc_offices SET
            county = v_contribution_record.submitted_county,
            constituency = v_constituency_name,
            constituency_code = v_constituency_id,
            office_location = v_contribution_record.submitted_office_location,
            landmark = v_contribution_record.submitted_landmark,
            latitude = v_contribution_record.submitted_latitude,
            longitude = v_contribution_record.submitted_longitude,
            verified = true,
            verified_at = NOW(),
            verifier_id = p_admin_id,
            verification_source = 'admin_dashboard',
            updated_at = NOW(),
            image_url = COALESCE(v_contribution_record.image_public_url, image_url),
            created_from_contribution_id = p_contribution_id
        WHERE id = v_existing_office_id
        RETURNING id INTO v_office_id;
        
        v_action_taken := 'updated';
    ELSE
        -- INSERT new office
        INSERT INTO iebc_offices (
            county, constituency, constituency_code, office_location, landmark,
            latitude, longitude, verified, verified_at, verifier_id, 
            verification_source, image_url, created_from_contribution_id
        ) VALUES (
            v_contribution_record.submitted_county,
            v_constituency_name,
            v_constituency_id,
            v_contribution_record.submitted_office_location,
            v_contribution_record.submitted_landmark,
            v_contribution_record.submitted_latitude,
            v_contribution_record.submitted_longitude,
            true,
            NOW(),
            p_admin_id,
            'admin_dashboard',
            v_contribution_record.image_public_url,
            p_contribution_id
        ) RETURNING id INTO v_office_id;
        
        v_action_taken := 'created';
    END IF;
    
    -- Update contribution status
    UPDATE iebc_office_contributions 
    SET status = 'verified',
        reviewer_id = p_admin_id,
        reviewed_at = NOW()
    WHERE id = p_contribution_id;
    
    -- Log the action
    INSERT INTO verification_log (
        contribution_id,
        action,
        actor,
        details
    ) VALUES (
        p_contribution_id,
        'verified',
        p_admin_id,
        jsonb_build_object(
            'office_id', v_office_id,
            'action_taken', v_action_taken,
            'constituency_used', v_constituency_name,
            'constituency_id', v_constituency_id,
            'debug_info', v_debug_info
        )
    );
    
    RETURN jsonb_build_object(
        'action', v_action_taken,
        'office_id', v_office_id,
        'contribution_id', p_contribution_id,
        'constituency_used', v_constituency_name,
        'debug', v_debug_info
    );
    
EXCEPTION
    WHEN OTHERS THEN
        INSERT INTO verification_log (
            contribution_id,
            action,
            actor,
            details
        ) VALUES (
            p_contribution_id,
            'failed',
            p_admin_id,
            jsonb_build_object(
                'error', SQLERRM,
                'constituency', v_constituency_name,
                'constituency_id', v_constituency_id,
                'debug_info', v_debug_info
            )
        );
        
        RETURN jsonb_build_object(
            'error', SQLERRM,
            'details', 'Failed to process contribution: ' || SQLERRM,
            'debug', v_debug_info
        );
END;
$$;


ALTER FUNCTION public.promote_contribution_to_office(p_contribution_id bigint, p_admin_id text, p_office_data jsonb) OWNER TO postgres;

