--
-- Name: search_offices_by_text_and_location(text, double precision, double precision, double precision, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.search_offices_by_text_and_location(search_query text, search_lat double precision DEFAULT NULL::double precision, search_lng double precision DEFAULT NULL::double precision, radius_km double precision DEFAULT 50, max_results integer DEFAULT 10) RETURNS TABLE(id integer, county text, constituency_name text, constituency text, office_location text, latitude double precision, longitude double precision, verified boolean, formatted_address text, landmark text, clean_office_location text, distance_km double precision, text_rank double precision, combined_score double precision)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
  RETURN QUERY
  WITH
  -- Step 1: Full-text search matches
  text_matches AS (
    SELECT
      o.id,
      o.county,
      o.constituency_name,
      o.constituency,
      o.office_location,
      o.latitude,
      o.longitude,
      o.verified,
      o.formatted_address,
      o.landmark,
      o.clean_office_location,
      ts_rank(
        to_tsvector('english',
          COALESCE(o.county, '') || ' ' ||
          COALESCE(o.constituency_name, '') || ' ' ||
          COALESCE(o.constituency, '') || ' ' ||
          COALESCE(o.office_location, '') || ' ' ||
          COALESCE(o.landmark, '') || ' ' ||
          COALESCE(o.formatted_address, '')
        ),
        plainto_tsquery('english', search_query)
      )::FLOAT AS text_rank
    FROM public.iebc_offices o
    WHERE
      o.latitude IS NOT NULL
      AND o.longitude IS NOT NULL
      AND o.verified = true
      AND (
        search_query = '' OR search_query IS NULL OR
        to_tsvector('english',
          COALESCE(o.county, '') || ' ' ||
          COALESCE(o.constituency_name, '') || ' ' ||
          COALESCE(o.constituency, '') || ' ' ||
          COALESCE(o.office_location, '') || ' ' ||
          COALESCE(o.landmark, '') || ' ' ||
          COALESCE(o.formatted_address, '')
        ) @@ plainto_tsquery('english', search_query)
      )
  ),
  -- Step 2: Add geographic distance
  with_distance AS (
    SELECT
      tm.*,
      CASE
        WHEN search_lat IS NOT NULL AND search_lng IS NOT NULL THEN
          (6371 * acos(
            LEAST(1.0, GREATEST(-1.0,
              cos(radians(search_lat)) * cos(radians(tm.latitude)) *
              cos(radians(tm.longitude) - radians(search_lng)) +
              sin(radians(search_lat)) * sin(radians(tm.latitude))
            ))
          ))::FLOAT
        ELSE NULL
      END AS distance_km
    FROM text_matches tm
  )
  -- Step 3: Combine text rank with proximity decay
  SELECT
    wd.id,
    wd.county,
    wd.constituency_name,
    wd.constituency,
    wd.office_location,
    wd.latitude,
    wd.longitude,
    wd.verified,
    wd.formatted_address,
    wd.landmark,
    wd.clean_office_location,
    wd.distance_km,
    wd.text_rank,
    (wd.text_rank *
      CASE
        WHEN wd.distance_km IS NULL THEN 1.0
        WHEN wd.distance_km = 0 THEN 10.0
        ELSE 1.0 / (1.0 + wd.distance_km / 10.0)
      END
    )::FLOAT AS combined_score
  FROM with_distance wd
  WHERE
    wd.distance_km IS NULL OR wd.distance_km <= radius_km
  ORDER BY combined_score DESC
  LIMIT max_results;
END;
$$;


ALTER FUNCTION public.search_offices_by_text_and_location(search_query text, search_lat double precision, search_lng double precision, radius_km double precision, max_results integer) OWNER TO postgres;

