--
-- Name: search_offices_fuzzy(text, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.search_offices_fuzzy(search_term text, limit_count integer DEFAULT 20) RETURNS TABLE(id bigint, county text, constituency_name text, office_location text, latitude double precision, longitude double precision, formatted_address text, match_score real)
    LANGUAGE plpgsql
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    o.id,
    o.county,
    o.constituency_name,
    o.office_location,
    o.latitude,
    o.longitude,
    o.formatted_address,
    (
      CASE
        WHEN LOWER(o.county) LIKE '%' || LOWER(search_term) || '%' THEN 3.0
        WHEN LOWER(o.constituency_name) LIKE '%' || LOWER(search_term) || '%' THEN 2.5
        WHEN LOWER(o.office_location) LIKE '%' || LOWER(search_term) || '%' THEN 2.0
        WHEN LOWER(o.landmark) LIKE '%' || LOWER(search_term) || '%' THEN 1.5
        WHEN LOWER(o.formatted_address) LIKE '%' || LOWER(search_term) || '%' THEN 1.0
        ELSE 0.5
      END
    ) AS match_score
  FROM public.iebc_offices o
  WHERE o.verified = true
    AND (
      LOWER(o.county) LIKE '%' || LOWER(search_term) || '%'
      OR LOWER(o.constituency_name) LIKE '%' || LOWER(search_term) || '%'
      OR LOWER(o.office_location) LIKE '%' || LOWER(search_term) || '%'
      OR LOWER(o.landmark) LIKE '%' || LOWER(search_term) || '%'
      OR LOWER(o.formatted_address) LIKE '%' || LOWER(search_term) || '%'
    )
  ORDER BY match_score DESC, o.county, o.constituency_name
  LIMIT limit_count;
END;
$$;


ALTER FUNCTION public.search_offices_fuzzy(search_term text, limit_count integer) OWNER TO postgres;

--
-- Name: FUNCTION search_offices_fuzzy(search_term text, limit_count integer); Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON FUNCTION public.search_offices_fuzzy(search_term text, limit_count integer) IS 'Fuzzy text search across office fields with relevance scoring';


--
-- Name: submit_signature(uuid, text, text, text, text, jsonb, text, jsonb, text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.submit_signature(petition_id uuid, voter_id text, voter_name text, constituency text, ward text, signature_payload jsonb, signature_value text, public_key jsonb, key_version text, device_id text) RETURNS uuid
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  signature_id UUID;
  existing_count INT;
BEGIN
  -- Check for existing signature
  SELECT COUNT(*) INTO existing_count
  FROM public.signatures
  WHERE petition_id = petition_id
    AND voter_id = voter_id;
  
  IF existing_count > 0 THEN
    RAISE EXCEPTION 'DUPLICATE_SIGNATURE';
  END IF;

  -- Insert new signature
  INSERT INTO public.signatures (
    petition_id,
    voter_id,
    voter_name,
    constituency,
    ward,
    signature_payload,
    signature_value,
    public_key,
    key_version,
    device_id,
    verification_status
  ) VALUES (
    petition_id,
    voter_id,
    voter_name,
    constituency,
    ward,
    signature_payload,
    signature_value,
    public_key,
    key_version,
    device_id,
    '{"verified": true, "method": "digital_signature", "timestamp": NOW()}'
  ) RETURNING id INTO signature_id;

  RETURN signature_id;
END;
$$;


ALTER FUNCTION public.submit_signature(petition_id uuid, voter_id text, voter_name text, constituency text, ward text, signature_payload jsonb, signature_value text, public_key jsonb, key_version text, device_id text) OWNER TO postgres;

--
-- Name: sync_contribution_geom(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.sync_contribution_geom() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.submitted_latitude IS NOT NULL AND NEW.submitted_longitude IS NOT NULL THEN
        NEW.geom := ST_SetSRID(ST_MakePoint(NEW.submitted_longitude, NEW.submitted_latitude), 4326);
    END IF;
    RETURN NEW;
END;
$$;


