--
-- Name: validate_api_key(text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.validate_api_key(p_key_hash text) RETURNS TABLE(id uuid, tier text, requests_today integer, is_active boolean, monthly_request_count integer, credits_balance integer, is_locked boolean, plan_status text, current_period_end timestamp with time zone, monthly_reset_date timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Reset monthly counter if past reset date
    UPDATE public.api_keys
    SET
        monthly_request_count = 0,
        monthly_reset_date = date_trunc('month', now()) + interval '1 month'
    WHERE key_hash = p_key_hash
      AND is_active = true
      AND monthly_reset_date <= now();

    -- Increment counters and return full billing context
    RETURN QUERY
    UPDATE public.api_keys
    SET
        last_used_at = now(),
        requests_today = api_keys.requests_today + 1,
        requests_this_month = api_keys.requests_this_month + 1,
        monthly_request_count = api_keys.monthly_request_count + 1
    WHERE key_hash = p_key_hash AND is_active = true
    RETURNING
        api_keys.id,
        api_keys.tier,
        api_keys.requests_today,
        api_keys.is_active,
        api_keys.monthly_request_count,
        api_keys.credits_balance,
        api_keys.is_locked,
        api_keys.plan_status,
        api_keys.current_period_end,
        api_keys.monthly_reset_date;
END;
$$;


ALTER FUNCTION public.validate_api_key(p_key_hash text) OWNER TO postgres;

--
-- Name: validate_constituency_exists(text, text); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE FUNCTION public.validate_constituency_exists(constituency_name text, county_name text) RETURNS integer
    LANGUAGE plpgsql
    SET search_path TO 'public', 'pg_temp'
    AS $$
DECLARE
  constituency_id INTEGER;
BEGIN
  SELECT id INTO constituency_id 
  FROM constituencies 
  WHERE name = constituency_name;
  
  IF constituency_id IS NULL THEN
    -- Try to create the constituency if it doesn't exist
    INSERT INTO constituencies (name, county_id, registration_target)
    VALUES (
      constituency_name,
      (SELECT id FROM counties WHERE name = county_name LIMIT 1),
      0
    )
    RETURNING id INTO constituency_id;
  END IF;
  
  RETURN constituency_id;
END;
$$;


