--
-- Name: map_landmarks_readable; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.map_landmarks_readable WITH (security_invoker='true') AS
 SELECT id,
    name,
    landmark_type,
    landmark_subtype,
    typical_accuracy_meters,
    triangulation_weight,
    verified,
    tags,
    public.st_astext(centroid) AS centroid_wkt,
    centroid AS centroid_geom
   FROM public.map_landmarks;


ALTER VIEW public.map_landmarks_readable OWNER TO postgres;

--
-- Name: map_landmarks_readable_view; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.map_landmarks_readable_view WITH (security_invoker='true') AS
 SELECT id,
    name,
    landmark_type,
    landmark_subtype,
    typical_accuracy_meters,
    triangulation_weight,
    verified,
    tags,
    centroid_wkt,
    public.st_x(public.st_geomfromtext(centroid_wkt)) AS centroid_lng,
    public.st_y(public.st_geomfromtext(centroid_wkt)) AS centroid_lat
   FROM public.map_landmarks_readable;


ALTER VIEW public.map_landmarks_readable_view OWNER TO postgres;

