--
-- Name: vw_contributions; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_contributions WITH (security_barrier='true', security_invoker='true') AS
 SELECT c.id,
    c.submitted_latitude,
    c.submitted_longitude,
    c.submitted_accuracy_meters,
    c.submitted_constituency,
    c.submitted_constituency_code,
    c.submitted_county,
    c.submitted_landmark,
    c.submitted_office_location,
    c.submitted_timestamp,
    c.reverse_geocode_result,
    c.nearby_landmarks,
    c.exif_metadata,
    c.device_metadata,
    c.device_fingerprint_hash,
    c.image_path,
    c.image_public_url,
    c.google_maps_link,
    c.original_office_id,
    c.duplicate_candidate_ids,
    c.confidence_score,
    c.confirmation_count,
    c.review_notes,
    c.reviewed_at,
    c.reviewer_id,
    c.status,
    c.geom,
    c.created_at,
    c.updated_at,
    o.office_location AS verified_office_location,
    o.verified AS office_verified,
    o.verified_at AS office_verified_at
   FROM (public.iebc_office_contributions c
     LEFT JOIN public.iebc_offices o ON ((c.original_office_id = o.id)))
  WHERE ((auth.uid() IS NOT NULL) OR (auth.uid() IN ( SELECT core_team.user_id
           FROM public.core_team
          WHERE (core_team.is_admin = true))));


ALTER VIEW public.vw_contributions OWNER TO postgres;

--
-- Name: VIEW vw_contributions; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON VIEW public.vw_contributions IS 'Secure view of contributions with RLS enforcement via security barrier';


--
-- Name: vw_offices; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_offices WITH (security_barrier='true', security_invoker='true') AS
 SELECT id,
    office_location,
    clean_office_location,
    constituency,
    constituency_code,
    constituency_name,
    county,
    latitude,
    longitude,
    formatted_address,
    landmark,
    landmark_type,
    landmark_subtype,
    direction_landmark,
    direction_type,
    direction_distance,
    distance_from_landmark,
    accuracy_meters,
    verification_source,
    verified,
    verified_at,
    verified_latitude,
    verified_longitude,
    verifier_id,
    notes,
    importance_score,
    geocode_method,
    geocode_status,
    geocode_confidence,
    geocode_query,
    successful_geocode_query,
    geocode_queries,
    total_queries_tried,
    result_type,
    source,
    contributor_image_url,
    geom,
    created_at,
    updated_at
   FROM public.iebc_offices
  WHERE ((verified = true) OR (auth.uid() IN ( SELECT core_team.user_id
           FROM public.core_team
          WHERE (core_team.is_admin = true))));


ALTER VIEW public.vw_offices OWNER TO postgres;

--
-- Name: VIEW vw_offices; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON VIEW public.vw_offices IS 'Secure view of IEBC offices with RLS enforcement via security barrier';


--
-- Name: vw_verification_status; Type: VIEW; Schema: public; Owner: postgres
--

CREATE VIEW public.vw_verification_status WITH (security_barrier='true', security_invoker='true') AS
 SELECT v.id,
    v.contribution_id,
    v.office_id,
    v.action,
    v.actor,
    v.details,
    v.created_at,
    c.submitted_office_location AS contribution_location,
    c.status AS contribution_status,
    o.office_location,
    o.verified AS office_verified
   FROM ((public.verification_log v
     LEFT JOIN public.iebc_office_contributions c ON ((v.contribution_id = c.id)))
     LEFT JOIN public.iebc_offices o ON ((v.office_id = o.id)))
  WHERE ((auth.uid() IS NOT NULL) OR (auth.uid() IN ( SELECT core_team.user_id
           FROM public.core_team
          WHERE (core_team.is_admin = true))));


ALTER VIEW public.vw_verification_status OWNER TO postgres;

--
-- Name: VIEW vw_verification_status; Type: COMMENT; Schema: public; Owner: postgres
--

COMMENT ON VIEW public.vw_verification_status IS 'Secure view of verification logs with RLS enforcement via security barrier';


