--
-- Name: security_audit_log security_audit_admin_access; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY security_audit_admin_access ON public.security_audit_log USING ((EXISTS ( SELECT 1
   FROM public.core_team
  WHERE ((core_team.user_id = auth.uid()) AND (core_team.is_active = true) AND (core_team.role = ANY (ARRAY['admin'::text, 'super_admin'::text]))))));


--
-- Name: security_audit_log; Type: ROW SECURITY; Schema: public; Owner: postgres
--

ALTER TABLE public.security_audit_log ENABLE ROW LEVEL SECURITY;

--
-- Name: security_audit_log security_audit_user_access; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY security_audit_user_access ON public.security_audit_log FOR SELECT USING (((user_id = auth.uid()) OR (((current_setting('request.jwt.claims'::text, true))::json ->> 'role'::text) = 'anon'::text)));


