-- Name: signatures signatures_insert_policy; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY signatures_insert_policy ON public.signatures FOR INSERT WITH CHECK (true);


--
-- Name: signatures signatures_select_authenticated_device; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY signatures_select_authenticated_device ON public.signatures FOR SELECT TO authenticated USING ((((device_id IS NOT NULL) AND ((auth.jwt() ->> 'device_id'::text) IS NOT NULL) AND (device_id = ((auth.jwt() ->> 'device_id'::text))::uuid)) OR public.is_admin(auth.uid())));


--
-- Name: signatures signatures_select_own; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY signatures_select_own ON public.signatures FOR SELECT USING ((((device_id IS NOT NULL) AND ((auth.jwt() ->> 'device_id'::text) IS NOT NULL) AND (device_id = ((auth.jwt() ->> 'device_id'::text))::uuid)) OR public.is_admin(auth.uid())));


